        final uri = Uri.parse('fractalforge://view?type=mandelbrot&zoom=NaN');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, isNull);
      });

      test('Infinity string for zoom returns null', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&zoom=Infinity');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, isNull);
      });
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Replayable controller mutation plan for one history entry.
///
/// A history entry is a complete fractal state: module id, parameters, and
/// view. Controllers that expose `loadState(moduleId, params, view)` can apply
/// that complete state in one step so module-specific params are normalized
/// against the recorded module. Older controller-like test doubles without
/// `loadState` keep the legacy incremental replay sequence.
final class HistoryControllerReplayPlan {
  HistoryControllerReplayPlan({
    required this.moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  })  : view = snapshotHistoryView(view),
        params = snapshotHistoryParams(params);

  factory HistoryControllerReplayPlan.fromEntry(HistoryEntry entry) {
    return HistoryControllerReplayPlan(
      moduleId: entry.moduleId,
      view: entry.view,
      params: entry.params,
    );
  }

  final String moduleId;
  final FractalViewState view;
  final Map<String, Object> params;

  void applyTo(Object controller) {
    if (_tryApplyCompleteState(controller)) return;
    _applyIncrementalState(controller);
  }

  bool _tryApplyCompleteState(Object controller) {
    final Function loadState;
    try {
      loadState = (controller as dynamic).loadState as Function;
    } on NoSuchMethodError {
      return false;
    }

    Function.apply(loadState, const [], {
      #moduleId: moduleId,
      #params: params,
      #view: view,
    });
    return true;
  }

  void _applyIncrementalState(Object controller) {
    final target = controller as dynamic;

    for (final paramEntry in params.entries) {
      try {
        target.updateParam(paramEntry.key, paramEntry.value);
      } catch (_) {
        // Parameter may not exist in current module.
      }
    }

    target.updateZoom(view.zoom);
    target.updatePan(view.pan);
    target.updateRotation(view.rotation);
  }
}

/// Applies a complete history entry to a controller-like object.
void applyHistoryEntryToController(HistoryEntry entry, Object controller) {
  HistoryControllerReplayPlan.fromEntry(entry).applyTo(controller);
}

import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Represents a visited location in fractal exploration history.
///
/// Each entry captures the complete state needed to restore a viewpoint:
/// - The fractal module (type) being viewed
/// - The view state (pan, zoom, rotation)
/// - The fractal parameters at that time
/// - Optional metadata like name (for favorites) and timestamp
///
/// {@category Models}
@immutable
class HistoryEntry {
  /// Unique identifier for this history entry.
  final String id;

  /// The fractal module ID (e.g., 'mandelbrot', 'julia').
  final String moduleId;

  /// The view state (pan, zoom, rotation) at this location.
  final FractalViewState view;

  /// The fractal parameters at this location.
  final Map<String, Object> params;

  /// When this location was visited.
  final DateTime visitedAt;

  /// Optional user-defined name for favorites.
  ///
  /// If non-null, this entry is considered a favorite.
  final String? name;

  /// Whether this entry is marked as a favorite.
  bool get isFavorite => name != null;

  /// Creates a new [HistoryEntry].
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// history entry remains replayable even when callers mutate their originals.
  HistoryEntry({
    required this.id,
    required this.moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    required this.visitedAt,
    this.name,
  })  : view = snapshotHistoryView(view),
        params = snapshotHistoryParams(params);

  /// Creates a history entry from the current fractal state.
  factory HistoryEntry.fromState({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    String? name,
  }) {
    return HistoryEntry(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      moduleId: moduleId,
      view: view,
      params: params,
      visitedAt: DateTime.now(),
      name: name,
    );
  }

  /// Creates a copy with the given fields replaced.
  HistoryEntry copyWith({
    String? id,
    String? moduleId,
    FractalViewState? view,
    Map<String, Object>? params,
    DateTime? visitedAt,
    String? name,
    bool clearName = false,
  }) {
    return HistoryEntry(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      view: view ?? this.view,
      params: params ?? this.params,
      visitedAt: visitedAt ?? this.visitedAt,
      name: clearName ? null : (name ?? this.name),
    );
  }

  /// Serializes this entry to a JSON-compatible map.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'params': params,
      'visitedAt': visitedAt.toIso8601String(),
      'name': name,
    };
  }

  /// Deserializes a history entry from a JSON map.
  static HistoryEntry fromJson(Map<String, Object?> json) {
    final viewJson = json['view'] as Map<String, Object?>? ?? {};
    return HistoryEntry(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      view: FractalViewState(
        pan: Vector2(
          (viewJson['panX'] as num? ?? 0).toDouble(),
          (viewJson['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (viewJson['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (viewJson['rotX'] as num? ?? 0).toDouble(),
          (viewJson['rotY'] as num? ?? 0).toDouble(),
          (viewJson['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      params: decodeHistoryParams(json['params'] as Map?),
      visitedAt: DateTime.tryParse(json['visitedAt'] as String? ?? '') ??
          DateTime.now(),
      name: json['name'] as String?,
    );
  }

  /// Generates a display label for this entry.
  ///
  /// If named, returns the name. Otherwise, returns a
  /// formatted description of the location.
  String get displayLabel {
    if (name != null) return name!;
    final zoomStr = view.zoom >= 10
        ? '${view.zoom.toStringAsFixed(0)}x'
        : '${view.zoom.toStringAsFixed(1)}x';
    return '$moduleId @ $zoomStr';
  }

  /// Checks if this entry represents the same location as another.
  ///
  /// Two entries are at the same location if they have the same
  /// module, view state, and parameters.
  bool isSameLocation(HistoryEntry other) {
    return isSameHistoryLocation(
      moduleId: moduleId,
      view: view,
      params: params,
      otherModuleId: other.moduleId,
      otherView: other.view,
      otherParams: other.params,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is HistoryEntry && other.id == id;
  }

  @override
  int get hashCode => id.hashCode;
}

import 'dart:convert';

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:vector_math/vector_math.dart';

HistoryEntry _entry({
  String moduleId = 'mandelbrot',
  double zoom = 1,
  Map<String, Object> params = const <String, Object>{},
}) {
  return HistoryEntry(
    id: 'entry-$moduleId-$zoom-${params.length}',
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: zoom,
      rotation: Vector3.zero(),
    ),
    params: params,
    visitedAt: DateTime.utc(2024),
  );
}

void main() {
  group('HistoryEntry location identity', () {
    test('treats matching module, view, and params as the same location', () {
      final first = _entry(params: {'iterations': 100, 'bailout': 4.0});
      final second = _entry(params: {'bailout': 4.0, 'iterations': 100});

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats parameter changes as a different location', () {
      final first = _entry(params: {'iterations': 100});
      final second = _entry(params: {'iterations': 250});

      expect(first.isSameLocation(second), isFalse);
    });

    test('treats JSON-like list parameter values as replayable values', () {
      final first = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });
      final second = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats view changes as a different location', () {
      final first = _entry(zoom: 1);
      final second = _entry(zoom: 2);

      expect(first.isSameLocation(second), isFalse);
    });

    test('snapshots mutable view vectors and params when created from state',
        () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    test('constructor snapshots mutable view and freezes nested params', () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry(
        id: 'entry',
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
        visitedAt: DateTime.utc(2024),
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(1.0);

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
      expect(
        () => entry.params['paletteStops'] = <Object?>[],
        throwsUnsupportedError,
      );
      expect(
        () => (entry.params['paletteStops'] as List<Object?>).add(1.0),
        throwsUnsupportedError,
      );
      expect(
        () => ((entry.params['paletteStops'] as List<Object?>)[1]
            as Map<String, Object?>)['position'] = 0.75,
        throwsUnsupportedError,
      );
    });

    test('serializes nested map parameter keys as JSON object keys', () {
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: <String, Object>{
          'metadata': <Object, Object>{1: 'one'},
        },
      );

      final encoded = jsonEncode(entry.toJson());
      final decoded = jsonDecode(encoded) as Map<String, Object?>;
      final restored = HistoryEntry.fromJson(decoded);

      expect(restored.params, {
        'metadata': {'1': 'one'},
      });
    });

    test('drops stale top-level null params while preserving replayable entry',
        () {
      final restored = HistoryEntry.fromJson({
        'id': 'entry-with-stale-param',
        'moduleId': 'mandelbrot',
        'view': <String, Object?>{
          'panX': 0,
          'panY': 0,
          'zoom': 1,
          'rotX': 0,
          'rotY': 0,
          'rotZ': 0,
        },
        'params': <String, Object?>{
          'iterations': 120,
          'staleNull': null,
          'paletteStops': <Object?>[
            0.0,
            null,
            <String, Object?>{'position': null},
          ],
        },
        'visitedAt': '2024-01-01T00:00:00.000Z',
        'name': null,
      });

      expect(restored.id, 'entry-with-stale-param');
      expect(restored.params, {
        'iterations': 120,
        'paletteStops': [
          0.0,
          null,
          {'position': null},
        ],
      });
    });

    test('deep-snapshots nested JSON-like params when created from state', () {
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
        1.0,
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: params,
      );

      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(2.0);

      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
          1.0,
        ],
      });
    });

    test('snapshots replacement view and params when copied', () {
      final replacementPan = Vector2(1, 2);
      final replacementRotation = Vector3(3, 4, 5);
      final replacementStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final replacementParams = <String, Object>{
        'paletteStops': replacementStops,
      };

      final copied = _entry().copyWith(
        view: FractalViewState(
          pan: replacementPan,
          zoom: 6,
          rotation: replacementRotation,
        ),
        params: replacementParams,
      );

      replacementPan.setValues(7, 8);
      replacementRotation.setValues(9, 10, 11);
      (replacementStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((replacementStops[1] as Map<String, Object?>)['rgb']
          as List<Object?>)[0] = 255;
      replacementStops.add(1.0);

      expect(copied.view.pan.x, 1);
      expect(copied.view.pan.y, 2);
      expect(copied.view.rotation.x, 3);
      expect(copied.view.rotation.y, 4);
      expect(copied.view.rotation.z, 5);
      expect(copied.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
    });
  });
}

import 'dart:convert';

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_provider.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';

FractalViewState _view(double zoom) {
  return FractalViewState(
    pan: Vector2.zero(),
    zoom: zoom,
    rotation: Vector3.zero(),
  );
}

Map<String, Object?> _entryJson(double zoom) {
  return HistoryEntry.fromState(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  ).toJson();
}

Future<void> _recordAndFlush(
  WidgetTester tester,
  HistoryProvider provider, {
  required double zoom,
}) async {
  provider.recordLocation(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  );
  await tester.pump(const Duration(milliseconds: 501));
}

final class _LegacyReplayController {
  final params = <String, Object>{};
  double? zoom;
  Vector2? pan;
  Vector3? rotation;

  void updateParam(String id, Object value) {
    params[id] = value;
  }

  void updateZoom(double value) {
    zoom = value;
  }

  void updatePan(Vector2 value) {
    pan = Vector2.copy(value);
  }

  void updateRotation(Vector3 value) {
    rotation = Vector3.copy(value);
  }
}

void main() {
  group('HistoryProvider navigation recording', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    testWidgets(
        'replaying the current back entry does not truncate forward history',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);
      await _recordAndFlush(tester, provider, zoom: 3);

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);

      await _recordAndFlush(tester, provider, zoom: 2);

      expect(provider.historyCount, 3);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);
      expect(provider.currentEntry, same(restored));
    });

    testWidgets('history navigation cancels pending pre-navigation records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(3),
        params: const <String, Object>{'iterations': 100},
      );

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(restored!.view.zoom, 1);
      expect(provider.currentPosition, 1);
      expect(provider.canGoForward, isTrue);

      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 2);
      expect(provider.currentPosition, 1);
      expect(provider.currentEntry, same(restored));
      expect(provider.canGoForward, isTrue);
      expect(provider.history.map((entry) => entry.view.zoom), [1, 2]);
    });

    testWidgets('records the state passed to the debounced record call',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;
      await tester.pump(const Duration(milliseconds: 501));

      final entry = provider.currentEntry;
      expect(entry, isNotNull);
      expect(entry!.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    testWidgets('keeps in-memory history capped to the persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++) {
        await _recordAndFlush(tester, provider, zoom: i + 1.0);
      }

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
    });

    testWidgets('keeps in-memory favorites capped to persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);

      for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++) {
        await provider.saveCurrentAsFavorite('favorite $i');
      }

      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.name, 'favorite 2');
      expect(provider.favorites.last.name, 'favorite 501');
      expect(store.loadFavorites().length, HistoryStore.maxFavoriteEntries);
    });

    testWidgets('restored history and favorites are capped before display',
        (tester) async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': jsonEncode([
          for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
        'exploration_favorites': jsonEncode([
          for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
      });

      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.view.zoom, 3.0);
      expect(provider.favorites.last.view.zoom, 502.0);
    });

    testWidgets('clearHistory cancels pending debounced records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(6),
        params: const <String, Object>{'iterations': 100},
      );
      await provider.clearHistory();
      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 0);
      expect(provider.currentEntry, isNull);
      expect(store.loadHistory(), isEmpty);
    });

    testWidgets('history replay switches to the recorded module before state',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final registry = ModuleRegistry();
      final controller = FractalController(registry);
      addTearDown(controller.dispose);

      final entry = HistoryEntry(
        id: 'julia-replay',
        moduleId: 'julia',
        view: FractalViewState(
          pan: Vector2(0.25, -0.5),
          zoom: 2.5,
          rotation: Vector3(0.1, 0.2, 0.3),
        ),
        params: const <String, Object>{
          'iterations': 222,
          'bailout': 4.5,
          'colorScheme': 2,
        },
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.module.id, 'julia');
      expect(controller.params['iterations'], 222);
      expect(controller.params['bailout'], closeTo(4.5, 1e-12));
      expect(controller.params['colorScheme'], 2);
      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.zoom, 2.5);
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });

    testWidgets('history replay keeps legacy structural controllers working',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final controller = _LegacyReplayController();
      final entry = HistoryEntry(
        id: 'legacy-replay',
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2(-0.25, 0.5),
          zoom: 3.5,
          rotation: Vector3(0.4, 0.5, 0.6),
        ),
        params: const <String, Object>{'iterations': 180},
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.params, {'iterations': 180});
      expect(controller.zoom, 3.5);
      expect(controller.pan, Vector2(-0.25, 0.5));
      expect(controller.rotation, Vector3(0.4, 0.5, 0.6));
    });
  });
}

import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

/// Creates an immutable-by-convention history snapshot of a mutable view state.
///
/// [FractalViewState] stores mutable vector_math objects, so history must clone
/// those vectors at the record boundary to keep debounced writes replayable.
FractalViewState snapshotHistoryView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

/// Creates a deep JSON-like snapshot of parameters at the record boundary.
Map<String, Object> snapshotHistoryParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: snapshotHistoryParamValue(entry.value),
  });
}

/// Decodes persisted history params without letting one stale null field drop
/// an otherwise replayable entry.
Map<String, Object> decodeHistoryParams(Map? params) {
  if (params == null) return const <String, Object>{};

  final decoded = <String, Object>{};
  for (final entry in params.entries) {
    final key = entry.key;
    final value = entry.value;
    if (key == null || value == null) continue;
    decoded[key.toString()] = snapshotHistoryParamValue(value as Object);
  }
  return Map<String, Object>.unmodifiable(decoded);
}

/// Deep-copies JSON-like parameter values so history replay is not affected by
/// later mutations of nested list/map values owned by controllers or widgets.
///
/// Nested map keys are normalized to strings because history entries are
/// persisted as JSON objects. Without this, a controller-owned metadata map
/// with enum/int keys can make the whole history save fail during jsonEncode.
/// Returned collections are unmodifiable so public [HistoryEntry] reads cannot
/// mutate stored history without going through provider methods.
Object snapshotHistoryParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? snapshotHistoryParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? snapshotHistoryParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// Pure location-equivalence contract for history de-duplication.
///
/// A history location is the restorable fractal state: module, view, and
/// parameters. Metadata such as entry id, favorite name, and timestamp is not
/// part of location identity.
bool isSameHistoryLocation({
  required String moduleId,
  required FractalViewState view,
  required Map<String, Object> params,
  required String otherModuleId,
  required FractalViewState otherView,
  required Map<String, Object> otherParams,
}) {
  if (moduleId != otherModuleId) {
    return false;
  }
  if (view.zoom != otherView.zoom) {
    return false;
  }
  if (view.pan.x != otherView.pan.x || view.pan.y != otherView.pan.y) {
    return false;
  }
  if (view.rotation.x != otherView.rotation.x ||
      view.rotation.y != otherView.rotation.y ||
      view.rotation.z != otherView.rotation.z) {
    return false;
  }
  return haveSameHistoryParams(params, otherParams);
}

/// Compares history parameter snapshots without relying on map iteration order.
bool haveSameHistoryParams(
  Map<String, Object> params,
  Map<String, Object> otherParams,
) {
  if (params.length != otherParams.length) {
    return false;
  }

  for (final entry in params.entries) {
    if (!otherParams.containsKey(entry.key)) {
      return false;
    }
    if (!areSameHistoryParamValue(entry.value, otherParams[entry.key])) {
      return false;
    }
  }

  return true;
}

/// Compares JSON-like history parameter values by value rather than identity.
///
/// Persisted params can contain nested lists/maps after JSON decode. Dart's
/// collection equality is identity-based, which would make two replayed
/// locations look different even when their serialized parameter values match.
bool areSameHistoryParamValue(Object? value, Object? otherValue) {
  if (identical(value, otherValue)) return true;

  if (value is List && otherValue is List) {
    if (value.length != otherValue.length) return false;
    for (var i = 0; i < value.length; i++) {
      if (!areSameHistoryParamValue(
          value[i] as Object?, otherValue[i] as Object?)) {
        return false;
      }
    }
    return true;
  }

  if (value is Map && otherValue is Map) {
    if (value.length != otherValue.length) return false;
    for (final entry in value.entries) {
      if (!otherValue.containsKey(entry.key)) return false;
      if (!areSameHistoryParamValue(
        entry.value as Object?,
        otherValue[entry.key] as Object?,
      )) {
        return false;
      }
    }
    return true;
  }

  return value == otherValue;
}

import 'dart:async' show Timer, unawaited;
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_favorites.dart';
import 'package:flutter_fractals/features/history/history_location.dart';
import 'package:flutter_fractals/features/history/history_replay.dart';
import 'package:flutter_fractals/features/history/history_window.dart';

/// Manages exploration history with back/forward navigation and favorites.
///
/// [HistoryProvider] tracks the user's journey through fractal space,
/// allowing them to:
/// - Navigate back to previously visited locations
/// - Navigate forward after going back
/// - Save favorite spots with custom names
/// - View and jump to any point in history
///
/// History is automatically persisted to local storage.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final history = HistoryProvider(store: historyStore);
///
/// // Record current location
/// history.recordLocation(
///   moduleId: 'mandelbrot',
///   view: controller.view,
///   params: controller.params,
/// );
///
/// // Navigate back
/// if (history.canGoBack) {
///   final entry = history.goBack();
///   // Apply entry to controller
/// }
/// ```
class HistoryProvider extends ChangeNotifier {
  final HistoryStore _store;

  /// All recorded history entries (oldest first).
  List<HistoryEntry> _history = [];

  /// Current position in history (index into _history).
  /// -1 means no history, 0+ is the index.
  int _currentIndex = -1;

  /// User's saved favorite locations.
  List<HistoryEntry> _favorites = [];

  /// Debounce timer to avoid recording too many entries during quick navigation.
  Timer? _debounceTimer;
  static const Duration _debounceDelay = Duration(milliseconds: 500);

  /// Last recorded state to detect meaningful changes.
  HistoryEntry? _lastRecorded;

  /// Creates a new [HistoryProvider].
  HistoryProvider({required HistoryStore store}) : _store = store {
    _loadFromStorage();
  }

  /// Whether navigation to a previous location is possible.
  bool get canGoBack => _currentIndex > 0;

  /// Whether navigation to a later location is possible.
  ///
  /// Only available after going back.
  bool get canGoForward => _currentIndex < _history.length - 1;

  /// The current history entry, if any.
  HistoryEntry? get currentEntry =>
      _currentIndex >= 0 && _currentIndex < _history.length
          ? _history[_currentIndex]
          : null;

  /// All history entries (oldest first).
  List<HistoryEntry> get history => List.unmodifiable(_history);

  /// Number of entries in history.
  int get historyCount => _history.length;

  /// Current position in history (1-indexed for display).
  int get currentPosition => _currentIndex + 1;

  /// All saved favorites.
  List<HistoryEntry> get favorites => List.unmodifiable(_favorites);

  /// Number of saved favorites.
  int get favoritesCount => _favorites.length;

  void _loadFromStorage() {
    final restored = HistoryRestorePolicy.restore(
      history: _store.loadHistory(),
      favorites: _store.loadFavorites(),
      maxHistoryEntries: HistoryStore.maxHistoryEntries,
      maxFavoriteEntries: HistoryStore.maxFavoriteEntries,
    );
    _history = restored.history;
    _favorites = restored.favorites;
    _currentIndex = restored.currentIndex;
    _lastRecorded = restored.currentEntry;
  }

  /// Records the current location in history.
  ///
  /// If the user has gone back and then makes a change,
  /// forward history is discarded (like a browser).
  ///
  /// Debounces rapid changes to avoid cluttering history
  /// with intermediate positions during smooth navigation.
  void recordLocation({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  }) {
    final viewSnapshot = snapshotHistoryView(view);
    final paramsSnapshot = snapshotHistoryParams(params);

    _debounceTimer?.cancel();
    _debounceTimer = Timer(_debounceDelay, () {
      _doRecordLocation(moduleId, viewSnapshot, paramsSnapshot);
    });
  }

  void _doRecordLocation(
    String moduleId,
    FractalViewState view,
    Map<String, Object> params,
  ) {
    final entry = HistoryEntry.fromState(
      moduleId: moduleId,
      view: view,
      params: params,
    );

    // Skip if essentially the same location as the last entry
    if (_lastRecorded != null && _lastRecorded!.isSameLocation(entry)) {
      return;
    }

    final window = HistoryWindowPolicy.append(
      entries: _history,
      currentIndex: _currentIndex,
      entry: entry,
      maxEntries: HistoryStore.maxHistoryEntries,
    );
    _history = window.entries;
    _currentIndex = window.currentIndex;
    _lastRecorded = entry;

    unawaited(_store.saveHistory(_history));
    notifyListeners();
  }

  /// Navigates back to the previous location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoBack] is false.
  HistoryEntry? goBack() {
    if (!canGoBack) return null;
    return jumpToIndex(_currentIndex - 1);
  }

  /// Navigates forward to the next location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoForward] is false.
  HistoryEntry? goForward() {
    if (!canGoForward) return null;
    return jumpToIndex(_currentIndex + 1);
  }

  /// Jumps to a specific entry in history by index.
  HistoryEntry? jumpToIndex(int index) {
    if (index < 0 || index >= _history.length) return null;
    _selectHistoryIndex(index);
    notifyListeners();
    return _history[_currentIndex];
  }

  void _selectHistoryIndex(int index) {
    assert(index >= 0 && index < _history.length);
    // A debounced record captures pre-navigation controller state. If it fires
    // after an explicit history jump, it can silently truncate forward history
    // and move the current entry away from the user's selected replay point.
    cancelPendingRecord();
    _currentIndex = index;
    _lastRecorded = _history[index];
  }

  /// Jumps to a specific entry in history by ID.
  HistoryEntry? jumpToEntry(String entryId) {
    final index = _history.indexWhere((e) => e.id == entryId);
    if (index < 0) return null;
    return jumpToIndex(index);
  }

  /// Saves the current location as a favorite.
  ///
  /// Creates a named copy of the current history entry.
  Future<void> saveCurrentAsFavorite(String name) async {
    if (currentEntry == null) return;

    final favorite = currentEntry!.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Saves a specific entry as a favorite.
  Future<void> saveAsFavorite(HistoryEntry entry, String name) async {
    final favorite = entry.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Removes a favorite by ID.
  Future<void> removeFavorite(String favoriteId) async {
    _favorites.removeWhere((f) => f.id == favoriteId);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Renames a favorite.
  Future<void> renameFavorite(String favoriteId, String newName) async {
    final index = _favorites.indexWhere((f) => f.id == favoriteId);
    if (index < 0) return;

    _favorites[index] = _favorites[index].copyWith(name: newName);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Checks if the current location is saved as a favorite.
  bool isCurrentFavorite() {
    if (currentEntry == null) return false;
    return _favorites.any((f) => f.isSameLocation(currentEntry!));
  }

  void _clearInMemoryHistory() {
    cancelPendingRecord();
    _history.clear();
    _currentIndex = -1;
    _lastRecorded = null;
  }

  /// Clears all history.
  Future<void> clearHistory() async {
    _clearInMemoryHistory();
    await _store.clearHistory();
    notifyListeners();
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    _favorites.clear();
    await _store.clearFavorites();
    notifyListeners();
  }

  /// Applies a history entry to a controller-like object.
  ///
  /// Complete-state controllers should expose `loadState` so replay switches to
  /// the recorded module before applying module-specific params. Legacy test
  /// doubles without `loadState` keep the old structural update sequence.
  void applyToController(HistoryEntry entry, Object controller) {
    applyHistoryEntryToController(entry, controller);
  }

  /// Cancels any pending debounced history record.
  void cancelPendingRecord() {
    _debounceTimer?.cancel();
    _debounceTimer = null;
  }

  @override
  void dispose() {
    cancelPendingRecord();
    super.dispose();
  }
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

HistoryEntry _makeEntry(String id, {String moduleId = 'mandelbrot'}) {
  return HistoryEntry(
    id: id,
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    params: {},
    visitedAt: DateTime.utc(2024, 1, 1),
  );
}

void main() {
  group('HistoryStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await HistoryStore.create();
      expect(store, isNotNull);
    });

    test('loadHistory returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('saveHistory and loadHistory round-trip entries', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('1', moduleId: 'mandelbrot'),
        _makeEntry('2', moduleId: 'julia'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(2));
      expect(loaded[0].id, equals('1'));
      expect(loaded[0].moduleId, equals('mandelbrot'));
      expect(loaded[1].id, equals('2'));
      expect(loaded[1].moduleId, equals('julia'));
    });

    test('history entries maintain insertion order', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('first', moduleId: 'mandelbrot'),
        _makeEntry('second', moduleId: 'julia'),
        _makeEntry('third', moduleId: 'burning_ship'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(3));
      expect(loaded[0].id, equals('first'));
      expect(loaded[1].id, equals('second'));
      expect(loaded[2].id, equals('third'));
    });

    test('saveHistory caps oldest-first history to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
          _makeEntry('history_$i'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(HistoryStore.maxHistoryEntries));
      expect(loaded.first.id, 'history_2');
      expect(loaded.last.id, 'history_${HistoryStore.maxHistoryEntries + 1}');
    });

    test('loadFavorites returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadFavorites(), isEmpty);
    });

    test('addFavorite appends entry to favorites', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav1'));
    });

    test('addFavorite does not duplicate existing entry', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
    });

    test('saveFavorites caps oldest-first favorites to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
          _makeEntry('favorite_$i'),
      ];

      await store.saveFavorites(entries);
      final loaded = store.loadFavorites();

      expect(loaded, hasLength(HistoryStore.maxFavoriteEntries));
      expect(loaded.first.id, 'favorite_2');
      expect(loaded.last.id, 'favorite_${HistoryStore.maxFavoriteEntries + 1}');
    });

    test('removeFavorite removes entry by ID', () async {
      final store = await HistoryStore.create();
      await store.addFavorite(_makeEntry('fav1'));
      await store.addFavorite(_makeEntry('fav2'));

      await store.removeFavorite('fav1');
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav2'));
    });

    test('clearHistory removes all history', () async {
      final store = await HistoryStore.create();
      await store.saveHistory([_makeEntry('1'), _makeEntry('2')]);

      await store.clearHistory();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory handles corrupted JSON gracefully', () async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': 'not valid json {{{',
      });
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory skips corrupted individual entries', () async {
      // Valid JSON array but one entry has missing required fields.
      SharedPreferences.setMockInitialValues({
        'exploration_history':
            '[{"id":"1","moduleId":"mandelbrot","view":{"panX":0,"panY":0,"zoom":1,"rotX":0,"rotY":0,"rotZ":0},"params":{},"visitedAt":"2024-01-01T00:00:00.000Z"},{"bad":"entry"}]',
      });
      final store = await HistoryStore.create();
      final loaded = store.loadHistory();
      // The valid entry should be present; the corrupted one silently skipped.
      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('1'));
    });
  });
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Pure favorite-list append policy shared by provider mutations.
///
/// Persistence caps favorites to keep local storage bounded. The provider must
/// apply the same cap before notifying listeners so in-memory UI state and the
/// next app launch agree about which favorites still exist.
class HistoryFavoritesPolicy {
  const HistoryFavoritesPolicy._();

  static List<HistoryEntry> append({
    required List<HistoryEntry> favorites,
    required HistoryEntry favorite,
    required int maxFavorites,
  }) {
    assert(maxFavorites > 0);

    final nextFavorites = List<HistoryEntry>.of(favorites)..add(favorite);
    if (nextFavorites.length > maxFavorites) {
      nextFavorites.removeRange(0, nextFavorites.length - maxFavorites);
    }
    return nextFavorites;
  }
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Result of applying a history-list mutation.
class HistoryWindow {
  /// History entries in display order (oldest first).
  final List<HistoryEntry> entries;

  /// Current selected index into [entries], or -1 when empty.
  final int currentIndex;

  const HistoryWindow({
    required this.entries,
    required this.currentIndex,
  });
}

/// Restored history and favorite lists after applying in-memory caps.
class HistoryRestoreSnapshot {
  final List<HistoryEntry> history;
  final int currentIndex;
  final List<HistoryEntry> favorites;

  const HistoryRestoreSnapshot({
    required this.history,
    required this.currentIndex,
    required this.favorites,
  });

  HistoryEntry? get currentEntry =>
      currentIndex >= 0 && currentIndex < history.length
          ? history[currentIndex]
          : null;
}

/// Pure storage-restore policy shared by provider boot and tests.
///
/// Storage writes are capped, but older/corrupted preferences can still contain
/// too many entries. Normalize immediately so first-frame UI state matches the
/// same bounded contract as persisted writes.
class HistoryRestorePolicy {
  const HistoryRestorePolicy._();

  static HistoryRestoreSnapshot restore({
    required List<HistoryEntry> history,
    required List<HistoryEntry> favorites,
    required int maxHistoryEntries,
    required int maxFavoriteEntries,
  }) {
    assert(maxHistoryEntries > 0);
    assert(maxFavoriteEntries > 0);

    final restoredHistory = _mostRecent(history, maxHistoryEntries);
    return HistoryRestoreSnapshot(
      history: restoredHistory,
      currentIndex: restoredHistory.isEmpty ? -1 : restoredHistory.length - 1,
      favorites: _mostRecent(favorites, maxFavoriteEntries),
    );
  }

  static List<HistoryEntry> _mostRecent(
    List<HistoryEntry> entries,
    int maxEntries,
  ) {
    if (entries.length <= maxEntries) return List<HistoryEntry>.of(entries);
    return entries.sublist(entries.length - maxEntries);
  }
}

/// Pure history append policy shared by recording and tests.
///
/// The in-memory provider must enforce the same maximum depth as persistence;
/// otherwise entries silently disappear only after app restart.
class HistoryWindowPolicy {
  const HistoryWindowPolicy._();

  static HistoryWindow append({
    required List<HistoryEntry> entries,
    required int currentIndex,
    required HistoryEntry entry,
    required int maxEntries,
  }) {
    assert(maxEntries > 0);

    final nextEntries = currentIndex >= 0 && currentIndex < entries.length - 1
        ? entries.sublist(0, currentIndex + 1)
        : List<HistoryEntry>.of(entries);

    nextEntries.add(entry);

    if (nextEntries.length > maxEntries) {
      nextEntries.removeRange(0, nextEntries.length - maxEntries);
    }

    return HistoryWindow(
      entries: nextEntries,
      currentIndex: nextEntries.length - 1,
    );
  }
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

/// Provenance for the custom export dimension that wins resolution.
enum CustomExportDimensionSource {
  fieldText,
  currentValue,
  fallback,
}

/// Replayable result of resolving one custom export dimension.
///
/// The export model clamps target dimensions later, but the sheet summary and
/// submission payload read [ExportOptions.customWidth]/customHeight directly.
/// Keep that boundary normalized too so all export dimension paths share the
/// same safety contract.
final class CustomExportDimensionResolution {
  const CustomExportDimensionResolution({
    required this.value,
    required this.source,
    required this.wasClamped,
  });

  final int value;
  final CustomExportDimensionSource source;
  final bool wasClamped;
}

CustomExportDimensionResolution resolveCustomExportDimensionPlan({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  return _normalizeCustomExportDimension(
        parsed,
        source: CustomExportDimensionSource.fieldText,
      ) ??
      _normalizeCustomExportDimension(
        currentValue,
        source: CustomExportDimensionSource.currentValue,
      ) ??
      _normalizeFallbackCustomExportDimension(fallback);
}

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  return resolveCustomExportDimensionPlan(
    fieldText: fieldText,
    currentValue: currentValue,
    fallback: fallback,
  ).value;
}

CustomExportDimensionResolution? _normalizeCustomExportDimension(
  int? value, {
  required CustomExportDimensionSource source,
}) {
  final normalized = ExportDimensionPolicy.positiveCustomDimension(value);
  if (normalized == null) return null;

  return CustomExportDimensionResolution(
    value: normalized,
    source: source,
    wasClamped: normalized != value,
  );
}

CustomExportDimensionResolution _normalizeFallbackCustomExportDimension(
  int fallback,
) {
  final safeFallback = fallback > 0 ? fallback : 1;
  final normalized = ExportDimensionPolicy.positiveCustomDimension(
    safeFallback,
  )!;

  return CustomExportDimensionResolution(
    value: normalized,
    source: CustomExportDimensionSource.fallback,
    wasClamped: normalized != fallback,
  );
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/custom_export_dimensions.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('resolveCustomExportDimension', () {
    test('uses positive field text before current value or fallback', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '2048',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        2048,
      );
    });

    test('falls back to current value when field text is invalid', () {
      expect(
        resolveCustomExportDimension(
          fieldText: 'not a number',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        1024,
      );
    });

    test('normalizes oversized field text through export dimension policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '${1 << 40}',
          currentValue: null,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });

    test('normalizes oversized current value fallback through policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '',
          currentValue: 1 << 40,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });
  });

  group('resolveCustomExportDimensionPlan', () {
    test('exposes winning source and clamp provenance', () {
      final clampedField = resolveCustomExportDimensionPlan(
        fieldText: '${1 << 40}',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );
      final currentFallback = resolveCustomExportDimensionPlan(
        fieldText: '0',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );

      expect(clampedField.value, ExportDimensionPolicy.maxPixelDimension);
      expect(clampedField.source, CustomExportDimensionSource.fieldText);
      expect(clampedField.wasClamped, isTrue);
      expect(currentFallback.value, 1024);
      expect(currentFallback.source, CustomExportDimensionSource.currentValue);
      expect(currentFallback.wasClamped, isFalse);
    });
  });

  group('withResolvedCustomExportDimensions', () {
    test('stores normalized custom dimensions in the export payload', () {
      final resolved = withResolvedCustomExportDimensions(
        options: const ExportOptions(
          resolution: ExportResolution.custom,
          customWidth: 1 << 40,
          customHeight: 720,
        ),
        widthText: '',
        heightText: '${1 << 35}',
      );

      expect(resolved.customWidth, ExportDimensionPolicy.maxPixelDimension);
      expect(resolved.customHeight, ExportDimensionPolicy.maxPixelDimension);
    });
  });
}

import 'package:equatable/equatable.dart';

/// Supported export image formats
enum ExportFormat {
  png,
  jpg,
  webp,
}

extension ExportFormatExtension on ExportFormat {
  String get extension {
    switch (this) {
      case ExportFormat.png:
        return 'png';
      case ExportFormat.jpg:
        return 'jpg';
      case ExportFormat.webp:
        return 'webp';
    }
  }

  String get mimeType {
    switch (this) {
      case ExportFormat.png:
        return 'image/png';
      case ExportFormat.jpg:
        return 'image/jpeg';
      case ExportFormat.webp:
        return 'image/webp';
    }
  }

  String get displayName {
    switch (this) {
      case ExportFormat.png:
        return 'PNG';
      case ExportFormat.jpg:
        return 'JPG';
      case ExportFormat.webp:
        return 'WebP';
    }
  }
}

/// Shared export dimension validation.
///
/// Screen dimensions and user-provided custom dimensions must resolve through
/// the same upper bound. Otherwise a typed custom size can bypass the safety
/// clamp used for invalid screen metrics and request an unreplayably huge
/// capture surface.
class ExportDimensionPolicy {
  static const int maxPixelDimension = 1 << 30;

  const ExportDimensionPolicy._();

  static int positiveRoundedScreenDimension(double value) {
    if (!value.isFinite || value <= 0) return 1;
    return value.round().clamp(1, maxPixelDimension);
  }

  static int? positiveCustomDimension(int? value) {
    if (value == null || value <= 0) return null;
    return value.clamp(1, maxPixelDimension);
  }
}

/// Preset resolution options for export
enum ExportResolution {
  screen, // Current screen resolution
  hd, // 1280x720
  fullHd, // 1920x1080
  quadHd, // 2560x1440
  uhd4k, // 3840x2160
  instagram, // 1080x1080 (square)
  instagramStory, // 1080x1920 (9:16)
  twitter, // 1200x675 (16:9)
  custom,
}

extension ExportResolutionExtension on ExportResolution {
  String get displayName {
    switch (this) {
      case ExportResolution.screen:
        return 'Screen';
      case ExportResolution.hd:
        return 'HD (1280×720)';
      case ExportResolution.fullHd:
        return 'Full HD (1920×1080)';
      case ExportResolution.quadHd:
        return '2K (2560×1440)';
      case ExportResolution.uhd4k:
        return '4K (3840×2160)';
      case ExportResolution.instagram:
        return 'Instagram (1080×1080)';
      case ExportResolution.instagramStory:
        return 'Instagram Story (1080×1920)';
      case ExportResolution.twitter:
        return 'Twitter (1200×675)';
      case ExportResolution.custom:
        return 'Custom';
    }
  }

  /// Returns (width, height) for preset resolutions
  /// Returns null for screen (use device size) or custom (user specified)
  (int, int)? get dimensions {
    switch (this) {
      case ExportResolution.screen:
        return null;
      case ExportResolution.hd:
        return (1280, 720);
      case ExportResolution.fullHd:
        return (1920, 1080);
      case ExportResolution.quadHd:
        return (2560, 1440);
      case ExportResolution.uhd4k:
        return (3840, 2160);
      case ExportResolution.instagram:
        return (1080, 1080);
      case ExportResolution.instagramStory:
        return (1080, 1920);
      case ExportResolution.twitter:
        return (1200, 675);
      case ExportResolution.custom:
        return null;
    }
  }

  bool get isSocialPreset {
    return this == ExportResolution.instagram ||
        this == ExportResolution.instagramStory ||
        this == ExportResolution.twitter;
  }
}

/// Metadata to embed in exported images
class ExportMetadata extends Equatable {
  final String? title;
  final String? description;
  final String fractalType;
  final Map<String, Object> parameters;
  final DateTime createdAt;
  final String appVersion;

  const ExportMetadata({
    this.title,
    this.description,
    required this.fractalType,
    required this.parameters,
    required this.createdAt,
    this.appVersion = '1.0.0',
  });

  Map<String, String> toExifMap() {
    return {
      'Software': 'Flutter Fractals $appVersion',
      'ImageDescription':
          description ?? 'Fractal artwork created with Flutter Fractals',
      'Artist': 'Flutter Fractals',
      'Copyright': '© ${createdAt.year} Flutter Fractals',
      'UserComment': _buildUserComment(),
    };
  }

  String _buildUserComment() {
    final buffer = StringBuffer();
    buffer.writeln('Fractal Type: $fractalType');
    buffer.writeln('Created: ${createdAt.toIso8601String()}');
    buffer.writeln('Parameters:');
    for (final entry in parameters.entries) {
      buffer.writeln('  ${entry.key}: ${entry.value}');
    }
    return buffer.toString();
  }

  @override
  List<Object?> get props =>
      [title, description, fractalType, parameters, createdAt, appVersion];
}

/// Complete export configuration
class ExportOptions extends Equatable {
  static const Object _unset = Object();

  final ExportFormat format;
  final ExportResolution resolution;
  final int? customWidth;
  final int? customHeight;
  final bool transparentBackground;
  final int quality; // 1-100, for JPG/WebP
  final bool embedMetadata;
  final ExportMetadata? metadata;
  final bool addWatermark;
  final String? watermarkText;

  const ExportOptions({
    this.format = ExportFormat.png,
    this.resolution = ExportResolution.fullHd,
    this.customWidth,
    this.customHeight,
    this.transparentBackground = false,
    this.quality = 95,
    this.embedMetadata = true,
    this.metadata,
    this.addWatermark = false,
    this.watermarkText,
  });

  static T? _nullableCopyWithValue<T>({
    required Object? candidate,
    required T? currentValue,
    required String fieldName,
  }) {
    assert(
      identical(candidate, _unset) || candidate == null || candidate is T,
      '$fieldName must be a $T? value',
    );

    return identical(candidate, _unset) ? currentValue : candidate as T?;
  }

  int _customOrScreenDimension(int? customValue, double screenValue) {
    return ExportDimensionPolicy.positiveCustomDimension(customValue) ??
        ExportDimensionPolicy.positiveRoundedScreenDimension(screenValue);
  }

  double _safeDimensionRatio(int targetDimension, double screenDimension) {
    final safeScreenDimension =
        ExportDimensionPolicy.positiveRoundedScreenDimension(screenDimension);
    return targetDimension / safeScreenDimension;
  }

  bool _preservesPresetOrientation() {
    return resolution.isSocialPreset;
  }

  (int, int)? _orientedPresetDimensions(
      double screenWidth, double screenHeight) {
    final dims = resolution.dimensions;
    if (dims == null) return null;

    final width = dims.$1;
    final height = dims.$2;
    final isPresetSquare = width == height;
    if (isPresetSquare || _preservesPresetOrientation()) return dims;

    final screenPortrait = screenHeight > screenWidth;
    final presetPortrait = height > width;

    if (screenPortrait != presetPortrait) {
      return (height, width);
    }

    return dims;
  }

  /// Calculate the pixel ratio needed to achieve target resolution
  double calculatePixelRatio(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      // Use the larger ratio to ensure we meet target resolution
      final widthRatio = _safeDimensionRatio(dims.$1, screenWidth);
      final heightRatio = _safeDimensionRatio(dims.$2, screenHeight);
      // Use max to ensure we hit the target resolution on both axes
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    if (resolution == ExportResolution.custom) {
      final targetWidth = _customOrScreenDimension(customWidth, screenWidth);
      final targetHeight = _customOrScreenDimension(customHeight, screenHeight);
      final widthRatio = _safeDimensionRatio(targetWidth, screenWidth);
      final heightRatio = _safeDimensionRatio(targetHeight, screenHeight);
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    return 2.5; // Default for screen resolution
  }

  /// Get the target dimensions for this export
  (int, int) getTargetDimensions(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      return dims;
    }

    if (resolution == ExportResolution.custom) {
      return (
        _customOrScreenDimension(customWidth, screenWidth),
        _customOrScreenDimension(customHeight, screenHeight),
      );
    }

    // Screen resolution
    return (
      ExportDimensionPolicy.positiveRoundedScreenDimension(screenWidth),
      ExportDimensionPolicy.positiveRoundedScreenDimension(screenHeight),
    );
  }

  ExportOptions copyWith({
    ExportFormat? format,
    ExportResolution? resolution,
    Object? customWidth = _unset,
    Object? customHeight = _unset,
    bool? transparentBackground,
    int? quality,
    bool? embedMetadata,
    Object? metadata = _unset,
    bool? addWatermark,
    Object? watermarkText = _unset,
  }) {
    assert(
      identical(metadata, _unset) ||
          metadata == null ||
          metadata is ExportMetadata,
      'metadata must be an ExportMetadata? value',
    );
    assert(
      identical(watermarkText, _unset) ||
          watermarkText == null ||
          watermarkText is String,
      'watermarkText must be a String? value',
    );

    return ExportOptions(
      format: format ?? this.format,
      resolution: resolution ?? this.resolution,
      customWidth: _nullableCopyWithValue<int>(
        candidate: customWidth,
        currentValue: this.customWidth,
        fieldName: 'customWidth',
      ),
      customHeight: _nullableCopyWithValue<int>(
        candidate: customHeight,
        currentValue: this.customHeight,
        fieldName: 'customHeight',
      ),
      transparentBackground:
          transparentBackground ?? this.transparentBackground,
      quality: quality ?? this.quality,
      embedMetadata: embedMetadata ?? this.embedMetadata,
      metadata: _nullableCopyWithValue<ExportMetadata>(
        candidate: metadata,
        currentValue: this.metadata,
        fieldName: 'metadata',
      ),
      addWatermark: addWatermark ?? this.addWatermark,
      watermarkText: _nullableCopyWithValue<String>(
        candidate: watermarkText,
        currentValue: this.watermarkText,
        fieldName: 'watermarkText',
      ),
    );
  }

  @override
  List<Object?> get props => [
        format,
        resolution,
        customWidth,
        customHeight,
        transparentBackground,
        quality,
        embedMetadata,
        metadata,
        addWatermark,
        watermarkText,
      ];
}

